import{_ as i,o as e,c as l,a0 as r}from"./chunks/framework.CSGB4SNl.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/java-hot200-day13.md","filePath":"java/eight-legged essay/java-hot200-day13.md"}'),s={name:"java/eight-legged essay/java-hot200-day13.md"};function o(t,a,d,h,n,c){return e(),l("div",null,[...a[0]||(a[0]=[r('<h4 id="如何优化java锁的使用" tabindex="-1">如何优化java锁的使用 <a class="header-anchor" href="#如何优化java锁的使用" aria-label="Permalink to &quot;如何优化java锁的使用&quot;">​</a></h4><ol><li>能不锁就不锁，锁的话越短越好</li><li>锁的范围进行把控，需要用到锁的那几行再用锁，还有就是把大锁拆成小锁，比如conHashMap1.8前是16个分区16把锁，后面直接改成每个桶的锁，就是把锁的颗粒度给细化了</li><li>读写分离，读的时候多个线程可以共享，写的时候要独占</li><li>还有就是能用CAS/原子类就别用锁</li><li>还有就是ThreadLocal每个线程持有自己的副本</li></ol><h4 id="redis的pipeline是什么" tabindex="-1">Redis的pipeline是什么 <a class="header-anchor" href="#redis的pipeline是什么" aria-label="Permalink to &quot;Redis的pipeline是什么&quot;">​</a></h4><ol><li>简单说就是pipeline让客户端把多条命令一次性打包给redis执行，不用等响应就可以执行下一条，这样的好处是减少网络往返次数</li></ol><h4 id="什么是服务雪崩" tabindex="-1">什么是服务雪崩 <a class="header-anchor" href="#什么是服务雪崩" aria-label="Permalink to &quot;什么是服务雪崩&quot;">​</a></h4><ol><li>就是一个服务挂掉，会导致其它调用他的服务像多米诺骨牌一样接连挂掉，就比如A调用B调用C，如果C崩掉了，B还在调用C请求的线程就会不断等待重试，然后整个线程池被占满，A此时调用B就会超时，然后A也不断重试，导致A那边也崩了</li><li>根本原因在于调用链过长，越长崩的越多，还有就是重试机制此时就是在帮倒忙，因为C服务快垮了，B还在不断重试调用就会直接导致C垮掉</li><li>措施简单来说就是熔断降级限流</li></ol><h4 id="jvm由那些部分构成" tabindex="-1">JVM由那些部分构成 <a class="header-anchor" href="#jvm由那些部分构成" aria-label="Permalink to &quot;JVM由那些部分构成&quot;">​</a></h4><ol><li>类加载器子系统、运行时数据区、执行引擎、外部调用接口-jni</li><li>类加载器就是负责将class文件从磁盘或网络拉进来</li><li>运行时数据区就负责存放这类class文件，包括代码、变量等</li><li>执行引擎就是负责翻译java字节码，弄成机器能看懂的指令执行</li><li>比如要调用c++等外部代码操作硬件相关的，就可以用jni</li><li>内存结构：堆(对象示例、数组)、虚拟机栈(方法执行局部变量)、本地方法栈(native方法)、方法区(类信息、静态变量、常量)、程序计数器-字节码行号</li><li>类加载过程：加载(读取class文件、生成Class对象)、验证(验证字节码是否合法)、准备(分配内存、初始化静态变量)、解析(符号引用-》直接引用)、初始化(初始化静态代码块、赋值)，双亲委派就是，在类加载过程中先看下是否能加载，不能则让其父类先加载，父类还不行就继续往上，以此类推</li><li>垃圾回收：计数器每个对象都有自己的计数器，被引用就加1，回收为0的-但是两个对象相互引用就没法回收，还有就是可达性分析-有点不是很懂，分代处理的原因是年轻代死的比较块、老年代死的慢，要对应分配垃圾回收算法</li></ol><h4 id="redis常用于哪些场景" tabindex="-1">redis常用于哪些场景 <a class="header-anchor" href="#redis常用于哪些场景" aria-label="Permalink to &quot;redis常用于哪些场景&quot;">​</a></h4><ol><li>核心就是做缓存、还有就是做分布式锁用-因为redis天生单线程保证原子性、高频计数器与限流，因为频繁修改数据库会出现锁竞争问题，用redis自增就保证原子性、复杂的排行表业务，数据量大数据库全表扫描就很消耗，用ZSet天然支持排序、也可以用redis List做轻量消息队列</li></ol><h4 id="什么是依赖循环" tabindex="-1">什么是依赖循环 <a class="header-anchor" href="#什么是依赖循环" aria-label="Permalink to &quot;什么是依赖循环&quot;">​</a></h4><ol><li>就是A和B的bean相互引用，就是你中有我我中有你，就是A需要B的工具才能干活，B也是，导致相互等待谁都没法初始化</li><li>解决方法就是抽离出公共依赖，或者延迟注入其中一个</li></ol><h4 id="redis中的bigkey是什么-如何解决" tabindex="-1">Redis中的bigkey是什么，如何解决 <a class="header-anchor" href="#redis中的bigkey是什么-如何解决" aria-label="Permalink to &quot;Redis中的bigkey是什么，如何解决&quot;">​</a></h4><ol><li>指的是redis中一个key的空间占有较大，通常会导致以下问题，指的是大key对应的value</li><li>redis单线程对大key操作较慢，会导致阻塞、客户端操作大key耗时长、网络传输中，大key占有的网络资源较多，导致网络传输时间延长或阻塞、内存分布不均，集群模式下，每个key对应每个示例的话，查询效率会受到影响</li><li>开发层面：大对象拆成多个小对象，将hash中的多个字段取模拆成更少的字段，选用合适数据结构，比如json数据更适合用hash存储</li><li>业务层面：redis只存相关数据，且把控存储量</li><li>还有就是redis数据分片可以将redis的大key拆成多个散落到不同节点下</li></ol>',14)])])}const k=i(s,[["render",o]]);export{_ as __pageData,k as default};
